#include <stdio.h>
#include <stdlib.h> // Required for malloc and free

int main() {
    int N;
    // Read the number of integers
    if (scanf("%d", &N) != 1 || N <= 0) {
        fprintf(stderr, "Invalid input for N. N must be a positive integer.\n");
        return 1;
    }

    // Dynamically allocate memory for N integers
    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    long long sum = 0; // Use long long for sum to prevent overflow for large N or values

    // Read N integers into the dynamically allocated array and calculate sum
    for (int i = 0; i < N; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            fprintf(stderr, "Invalid input for array element.\n");
            free(arr); // Free memory before exiting on error
            return 1;
        }
        sum += arr[i];
    }

    // Print the total sum
    printf("%lld\n", sum);

    // Free the dynamically allocated memory
    free(arr);
    arr = NULL; // Good practice to set pointer to NULL after freeing

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free
#include <string.h> // Required for strlen and strcpy

int main() {
    char input_buffer[101]; // Buffer for input string, +1 for null terminator
    if (scanf("%s", input_buffer) != 1) {
        fprintf(stderr, "Failed to read input string.\n");
        return 1;
    }

    int len = strlen(input_buffer);

    // Dynamically allocate memory for the reversed string
    // +1 for the null terminator
    char *reversed_str = (char *)malloc((len + 1) * sizeof(char));
    if (reversed_str == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    // Reverse the string
    for (int i = 0; i < len; i++) {
        reversed_str[i] = input_buffer[len - 1 - i];
    }
    reversed_str[len] = '\0'; // Null-terminate the reversed string

    // Print the reversed string
    printf("%s\n", reversed_str);

    // Free the dynamically allocated memory
    free(reversed_str);
    reversed_str = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free

int main() {
    int N;
    // Read matrix size N
    if (scanf("%d", &N) != 1 || N < 1 || N > 10) {
        fprintf(stderr, "Invalid input for N. N must be between 1 and 10.\n");
        return 1;
    }

    // Dynamically allocate memory for the 2D array (array of pointers to int)
    int **matrix = (int **)malloc(N * sizeof(int *));
    if (matrix == NULL) {
        fprintf(stderr, "Memory allocation failed for matrix rows.\n");
        return 1;
    }

    // Dynamically allocate memory for each row
    for (int i = 0; i < N; i++) {
        matrix[i] = (int *)malloc(N * sizeof(int));
        if (matrix[i] == NULL) {
            fprintf(stderr, "Memory allocation failed for matrix column %d.\n", i);
            // Free previously allocated rows before exiting
            for (int j = 0; j < i; j++) {
                free(matrix[j]);
            }
            free(matrix);
            return 1;
        }
    }

    // Read matrix elements
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (scanf("%d", &matrix[i][j]) != 1) {
                fprintf(stderr, "Invalid input for matrix element.\n");
                // Free all allocated memory before exiting on error
                for (int k = 0; k < N; k++) {
                    free(matrix[k]);
                }
                free(matrix);
                return 1;
            }
        }
    }

    long long sum_diagonals = 0;

    // Calculate sum of main diagonal and anti-diagonal
    for (int i = 0; i < N; i++) {
        sum_diagonals += matrix[i][i]; // Main diagonal
        sum_diagonals += matrix[i][N - 1 - i]; // Anti-diagonal
    }

    // If N is odd, the center element was added twice, so subtract it once
    if (N % 2 == 1) {
        sum_diagonals -= matrix[N / 2][N / 2];
    }

    printf("%lld\n", sum_diagonals);

    // Free all dynamically allocated memory
    for (int i = 0; i < N; i++) {
        free(matrix[i]);
    }
    free(matrix);
    matrix = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc, realloc, and free

int main() {
    int *arr = NULL;
    int capacity = 2; // Initial capacity
    int count = 0;    // Current number of elements

    // Allocate initial memory
    arr = (int *)malloc(capacity * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Initial memory allocation failed.\n");
        return 1;
    }

    int num;
    while (scanf("%d", &num) == 1 && num >= 0) {
        // If array is full, reallocate to double the capacity
        if (count == capacity) {
            capacity *= 2;
            int *temp = (int *)realloc(arr, capacity * sizeof(int));
            if (temp == NULL) {
                fprintf(stderr, "Memory reallocation failed.\n");
                free(arr); // Free original memory block
                return 1;
            }
            arr = temp; // Update array pointer to the new memory block
        }
        arr[count++] = num; // Add the number and increment count
    }

    // Print all stored numbers
    for (int i = 0; i < count; i++) {
        printf("%d\n", arr[i]);
    }

    // Free the dynamically allocated memory
    free(arr);
    arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free

int main() {
    int N;
    // Read the number of integers
    if (scanf("%d", &N) != 1 || N < 1 || N > 100) {
        fprintf(stderr, "Invalid input for N. N must be between 1 and 100.\n");
        return 1;
    }

    // Dynamically allocate memory for N integers
    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    // Read N integers into the array
    for (int i = 0; i < N; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            fprintf(stderr, "Invalid input for array element.\n");
            free(arr);
            return 1;
        }
    }

    long long even_sum = 0;
    int even_count = 0;

    // Iterate to find even numbers and calculate their sum and count
    for (int i = 0; i < N; i++) {
        if (arr[i] % 2 == 0) {
            even_sum += arr[i];
            even_count++;
        }
    }

    // Print the result based on whether even numbers were found
    if (even_count > 0) {
        printf("%lld\n", even_sum / even_count);
    } else {
        printf("No even numbers.\n");
    }

    // Free the dynamically allocated memory
    free(arr);
    arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free
#include <string.h> // Required for strlen, strcpy, and strcat

int main() {
    char s1_buffer[51]; // Buffer for s1, +1 for null terminator
    char s2_buffer[51]; // Buffer for s2, +1 for null terminator

    // Read the first string
    if (scanf("%50s", s1_buffer) != 1) { // %50s to prevent buffer overflow
        fprintf(stderr, "Failed to read first string.\n");
        return 1;
    }

    // Read the second string
    if (scanf("%50s", s2_buffer) != 1) { // %50s to prevent buffer overflow
        fprintf(stderr, "Failed to read second string.\n");
        return 1;
    }

    int len1 = strlen(s1_buffer);
    int len2 = strlen(s2_buffer);

    // Dynamically allocate memory for the concatenated string
    // len1 + len2 for characters + 1 for the null terminator
    char *concatenated_str = (char *)malloc((len1 + len2 + 1) * sizeof(char));
    if (concatenated_str == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    // Copy s1 to the new string
    strcpy(concatenated_str, s1_buffer);

    // Append s2 to the new string
    strcat(concatenated_str, s2_buffer);

    // Print the concatenated string
    printf("%s\n", concatenated_str);

    // Free the dynamically allocated memory
    free(concatenated_str);
    concatenated_str = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free
#include <string.h> // Required for strlen and strcpy

// Define the Student structure
struct Student {
    int id;
    char *name; // Pointer to dynamically allocated name string
};

int main() {
    int N;
    // Read the number of students
    if (scanf("%d", &N) != 1 || N < 1 || N > 5) {
        fprintf(stderr, "Invalid input for N. N must be between 1 and 5.\n");
        return 1;
    }

    // Dynamically allocate an array of Student structures
    struct Student *students = (struct Student *)malloc(N * sizeof(struct Student));
    if (students == NULL) {
        fprintf(stderr, "Memory allocation failed for students array.\n");
        return 1;
    }

    // Consume the newline character left by scanf("%d", &N)
    while (getchar() != '\n'); 

    char name_buffer[21]; // Buffer for reading student names, +1 for null terminator

    // Read data for each student
    for (int i = 0; i < N; i++) {
        printf("Enter ID for student %d: ", i + 1); // Prompt for user (not part of required stdin/stdout, just for user clarity)
        if (scanf("%d", &students[i].id) != 1) {
            fprintf(stderr, "Invalid input for student ID.\n");
            // Free memory allocated so far before exiting
            for (int j = 0; j < i; j++) {
                free(students[j].name);
            }
            free(students);
            return 1;
        }

        // Consume the newline character left by scanf("%d", &students[i].id)
        while (getchar() != '\n'); 

        printf("Enter name for student %d: ", i + 1); // Prompt for user
        // Read name using fgets to handle spaces (if names were multiple words, though constraint says single word)
        // For single word, scanf("%20s", name_buffer) is fine. Using fgets for general robustness for a line input.
        if (fgets(name_buffer, sizeof(name_buffer), stdin) == NULL) {
            fprintf(stderr, "Failed to read student name.\n");
            // Free memory allocated so far before exiting
            for (int j = 0; j < i; j++) {
                free(students[j].name);
            }
            free(students);
            return 1;
        }
        name_buffer[strcspn(name_buffer, "\n")] = 0; // Remove trailing newline if fgets read one

        // Dynamically allocate memory for the student's name
        students[i].name = (char *)malloc((strlen(name_buffer) + 1) * sizeof(char));
        if (students[i].name == NULL) {
            fprintf(stderr, "Memory allocation failed for student name %d.\n", i);
            // Free memory allocated so far before exiting
            for (int j = 0; j < i; j++) {
                free(students[j].name);
            }
            free(students);
            return 1;
        }
        strcpy(students[i].name, name_buffer);
    }

    // Print all student records
    for (int i = 0; i < N; i++) {
        printf("%d %s\n", students[i].id, students[i].name);
    }

    // Free dynamically allocated memory for each name, then for the array of structs
    for (int i = 0; i < N; i++) {
        free(students[i].name);
        students[i].name = NULL;
    }
    free(students);
    students = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free

int main() {
    int N;
    // Read the number of integers
    if (scanf("%d", &N) != 1 || N < 1 || N > 100) {
        fprintf(stderr, "Invalid input for N. N must be between 1 and 100.\n");
        return 1;
    }

    // Dynamically allocate memory for N integers
    int *arr = (int *)malloc(N * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    // Read N integers into the array
    for (int i = 0; i < N; i++) {
        if (scanf("%d", &arr[i]) != 1) {
            fprintf(stderr, "Invalid input for array element.\n");
            free(arr);
            return 1;
        }
    }

    int max_val = arr[0];
    int max_idx = 0;

    // Iterate through the array to find the maximum value and its first index
    for (int i = 1; i < N; i++) {
        if (arr[i] > max_val) {
            max_val = arr[i];
            max_idx = i;
        }
    }

    // Print the maximum value and its index
    printf("%d %d\n", max_val, max_idx);

    // Free the dynamically allocated memory
    free(arr);
    arr = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc and free
#include <string.h> // Required for strlen and strcspn

int main() {
    char buffer[101]; // Buffer to read the line of text
    char char_to_find;
    int count = 0;

    // Read the line of text using fgets to handle spaces
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        fprintf(stderr, "Failed to read input line.\n");
        return 1;
    }
    buffer[strcspn(buffer, "\n")] = 0; // Remove trailing newline

    // Dynamically allocate memory for the string and copy the content
    char *dynamic_str = (char *)malloc((strlen(buffer) + 1) * sizeof(char));
    if (dynamic_str == NULL) {
        fprintf(stderr, "Memory allocation failed for dynamic string.\n");
        return 1;
    }
    strcpy(dynamic_str, buffer);

    // Read the character to find (note space before %c to consume potential leftover newline)
    if (scanf(" %c", &char_to_find) != 1) {
        fprintf(stderr, "Failed to read character to find.\n");
        free(dynamic_str);
        return 1;
    }

    // Count occurrences of the character in the dynamic string
    for (int i = 0; dynamic_str[i] != '\0'; i++) {
        if (dynamic_str[i] == char_to_find) {
            count++;
        }
    }

    // Print the total count
    printf("%d\n", count);

    // Free the dynamically allocated memory
    free(dynamic_str);
    dynamic_str = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for malloc, realloc, free
#include <string.h> // Required for strlen, strcpy, strtok

int main() {
    char line_buffer[101]; // Buffer for reading the entire line
    char *token;
    char **words = NULL; // Pointer to an array of char pointers
    int num_words = 0;
    int capacity = 5; // Initial capacity for the words array

    // Read the entire line of text
    if (fgets(line_buffer, sizeof(line_buffer), stdin) == NULL) {
        fprintf(stderr, "Failed to read input line.\n");
        return 1;
    }
    line_buffer[strcspn(line_buffer, "\n")] = 0; // Remove trailing newline

    // If the line is empty after stripping newline (or was just a newline), print newline and exit
    if (strlen(line_buffer) == 0) {
        printf("\n");
        return 0;
    }

    // Allocate initial memory for pointers to words
    words = (char **)malloc(capacity * sizeof(char *));
    if (words == NULL) {
        fprintf(stderr, "Initial memory allocation failed for word pointers.\n");
        return 1;
    }

    // Use strtok to tokenize the string
    char *mutable_line = strdup(line_buffer); // Create a mutable copy for strtok
    if (mutable_line == NULL) {
        fprintf(stderr, "Memory allocation failed for mutable line.\n");
        free(words);
        return 1;
    }

    token = strtok(mutable_line, " ");
    while (token != NULL) {
        // If capacity is reached, reallocate to double the capacity
        if (num_words == capacity) {
            capacity *= 2;
            char **temp = (char **)realloc(words, capacity * sizeof(char *));
            if (temp == NULL) {
                fprintf(stderr, "Memory reallocation failed for word pointers.\n");
                // Free already allocated word strings
                for (int i = 0; i < num_words; i++) {
                    free(words[i]);
                }
                free(words);
                free(mutable_line);
                return 1;
            }
            words = temp;
        }

        // Dynamically allocate memory for the current word and copy it
        words[num_words] = (char *)malloc((strlen(token) + 1) * sizeof(char));
        if (words[num_words] == NULL) {
            fprintf(stderr, "Memory allocation failed for word '%s'.\n", token);
            // Free already allocated word strings and pointers array
            for (int i = 0; i < num_words; i++) {
                free(words[i]);
            }
            free(words);
            free(mutable_line);
            return 1;
        }
        strcpy(words[num_words], token);
        num_words++;

        token = strtok(NULL, " ");
    }

    // Print words in reverse order
    for (int i = num_words - 1; i >= 0; i--) {
        printf("%s%s", words[i], (i == 0) ? "" : " ");
    }
    printf("\n"); // Newline at the very end

    // Free all dynamically allocated memory
    for (int i = 0; i < num_words; i++) {
        free(words[i]); // Free each individual word string
    }
    free(words); // Free the array of char pointers
    free(mutable_line); // Free the mutable copy of the input line
    words = NULL;
    mutable_line = NULL;

    return 0;
}
